import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import Navbar from "./Navbar";
import StudentProfile from "./StudentProfile";
import NotificationPanel from "./NotificationPanel";
import "../Styles/dashboard.css";
import profileImg from "../assets/classroom.jpg"; // Placeholder

const StudentDashboard = () => {
    const navigate = useNavigate();
    const [user, setUser] = useState({ name: "Student", email: "" });

    useEffect(() => {
        const token = localStorage.getItem("token");
        const role = localStorage.getItem("role");

        if (!token || role !== "student") {
            navigate("/");
        }

        // Mock Data
        setUser({
            name: "SHAH HEVAL SAURABH",
            course: "PIET-1 - BTech - CSE (Semester - 7)",
            id: "2203031050600",
            enrollment: "489151946194",
            dob: "16-04-2005",
            mobile: "9054621078 | 8000222004",
            motherName: "Kaksha",
            email: "hevalshah2056@gmail.com",
            profileImg: profileImg
        });
    }, [navigate]);

    const handleLogout = () => {
        localStorage.removeItem("token");
        localStorage.removeItem("role");
        navigate("/");
    };

    return (
        <div className="dashboard-layout">
            <Navbar user={user} onLogout={handleLogout} />

            <div className="dashboard-main-container">
                <div className="dashboard-header-title">
                    <h2>Dashboard <span className="student-name-light">{user.name}</span></h2>
                </div>

                {/* Note Section */}
                <div className="note-section">
                    <div className="note-content">
                        <strong>NOTE :</strong>
                        <p>Your Application Form cannot be generated without the following:</p>
                        <ul>
                            <li>Payment of Semester Fees</li>
                            <li>Payment of Hostel Fees</li>
                            <li>Uploaded documents</li>
                            <li>Fully filled student profile information</li>
                        </ul>
                    </div>
                </div>

                {/* Profile Completion Alert */}
                <div className="profile-alert">
                    <i className="fas fa-info-circle"></i> Kindly fill & confirm the profile to print admission form. <a href="#">Click Here</a> to complete your profile
                </div>

                <div className="dashboard-grid">
                    {/* Left Column: Profile */}
                    <div className="grid-column left-col">
                        <StudentProfile user={user} />
                    </div>

                    {/* Center Column: Mobile App Promo (Optional/Placeholder) */}
                    <div className="grid-column center-col">
                        <div className="mobile-app-card">
                            <div className="mobile-content">
                                <i className="fas fa-mobile-alt mobile-icon"></i>
                                <h3>Activate Your Mobile Application</h3>
                                <button className="activate-btn">Activate</button>
                            </div>
                        </div>
                    </div>

                    {/* Right Column: Notifications & Other Widgets */}
                    <div className="grid-column right-col">
                        <div className="transport-card">
                            <div className="card-header-red">
                                <i className="fas fa-bus"></i> Transport Registrations Open For <strong>Academic Year: 2025-26</strong> <span className="badge-pending">Pending</span>
                            </div>
                            <div className="card-body">
                                <p>Dear Students, Transport Registration for <strong>Academic Year: 2025-26</strong> has started. Kindly complete your registration on or before <strong>31-12-2025</strong>.</p>
                                <button className="register-btn">Click to Register »</button>
                            </div>
                        </div>

                        <div className="certificate-card">
                            <h3>Certificate Request</h3>
                            <a href="#">Click Here To Generate The Certificate</a>
                        </div>

                        {/* Notification Panel moved here or below as per layout preference */}
                    </div>
                </div>

                {/* Notification Panel - Full Width or Grid */}
                <div className="notification-section-wrapper">
                    <NotificationPanel />
                </div>

            </div>
        </div>
    );
};

export default StudentDashboard;
